```rust
// src/main.rs
mod provider;
mod utils;

use std::collections::HashMap;
use std::fs;

use clap::{Parser, Subcommand};

use provider::{
    Provider,
    digitalocean::{DigitalOceanCredentials, DigitalOceanProvider},
    gcp::{GcpCredentials, GcpProvider, print_build_credential},
};
use utils::{expand_tilde, prompt_yes_no, read_ssh_public_key};

// ---------------------------------------------------------------------------
// CLI
// ---------------------------------------------------------------------------

/// Maglev — multi-cloud Kubernetes cluster manager
#[derive(Parser)]
#[command(
    name = "maglev",
    version,
    about = "Provision and manage cloud-backed Kubernetes clusters"
)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Create VM instances described by a provider YAML config
    Apply {
        /// Path to the YAML config file (gcp.yaml or digitalocean.yaml)
        #[arg(default_value = "config/gcp.yaml")]
        config: String,
    },
    /// Permanently delete VM instances described by a provider YAML config
    Destroy {
        /// Path to the YAML config file
        #[arg(default_value = "config/gcp.yaml")]
        config: String,
    },
    /// Provision Kubernetes on control-plane nodes and join workers
    Play {
        /// Path to the YAML config file
        #[arg(default_value = "config/gcp.yaml")]
        config: String,
    },
    /// Run the interactive GCP credential builder
    Print,
}

// ---------------------------------------------------------------------------
// ip-address field type
// ---------------------------------------------------------------------------

/// Validated value for `ip-address` in a spec config block.
///
/// Accepted YAML values: `"public"` or `"private"`.
/// Omitting the field is equivalent to `"private"`.
#[derive(Debug, Clone, Copy, PartialEq, serde::Deserialize, serde::Serialize)]
#[serde(rename_all = "lowercase", deny_unknown_fields)]
enum IpAddressType {
    Public,
    Private,
}

impl Default for IpAddressType {
    fn default() -> Self {
        IpAddressType::Private
    }
}

impl std::fmt::Display for IpAddressType {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            IpAddressType::Public => write!(f, "public"),
            IpAddressType::Private => write!(f, "private"),
        }
    }
}

// ---------------------------------------------------------------------------
// Shared YAML types
// ---------------------------------------------------------------------------

/// A named group of nodes with a role type (`control-plane` or `worker`).
#[derive(Debug, serde::Deserialize, serde::Serialize)]
struct GroupYaml {
    name: String,
    /// Role of this group: `"control-plane"` or `"worker"`.
    #[serde(rename = "type")]
    group_type: String,
    node: Vec<String>,
}

/// A named spec whose config entries hold *all* VM + identity settings.
/// Every field is optional because a rule merges several spec entries
/// together — complementary fields live in different named specs.
#[derive(Debug, serde::Deserialize, serde::Serialize)]
struct SpecYaml {
    name: String,
    config: Vec<SpecConfigYaml>,
}

/// One config block inside a spec.  All fields are optional so that a
/// "base" spec (e.g. `cisak`) can supply identity/script fields while a
/// "role" spec (e.g. `control-plane-public`) supplies size/ip fields.
/// The rule engine merges them (first-wins per field).
#[derive(Debug, Clone, serde::Deserialize, serde::Serialize)]
struct SpecConfigYaml {
    #[serde(rename = "machine-type", default, skip_serializing_if = "Option::is_none")]
    machine_type: Option<String>,
    #[serde(rename = "boot-disk-image", default, skip_serializing_if = "Option::is_none")]
    boot_disk_image: Option<String>,
    #[serde(rename = "boot-disk-size", default, skip_serializing_if = "Option::is_none")]
    boot_disk_size: Option<u64>,
    /// `None` means the spec does not express a preference; the merge
    /// defaults to `Private` when no spec in the rule sets this field.
    #[serde(rename = "ip-address", default, skip_serializing_if = "Option::is_none")]
    ip_address: Option<IpAddressType>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    script: Option<String>,
    #[serde(rename = "ssh-public-key", default, skip_serializing_if = "Option::is_none")]
    ssh_public_key: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    user: Option<String>,
    /// Optional stable address for the Kubernetes API server load-balancer.
    /// Format: `<host>` or `<host>:<port>` (port defaults to 6443).
    #[serde(
        rename = "control-plane-endpoint",
        default,
        skip_serializing_if = "Option::is_none"
    )]
    control_plane_endpoint: Option<String>,
}

/// A rule now maps **lists** of group names to **lists** of spec names.
/// The spec configs are merged (first-wins) to produce one effective config.
#[derive(Debug, serde::Deserialize, serde::Serialize)]
struct RuleYaml {
    /// One or more group names this rule applies to.
    group: Vec<String>,
    /// Ordered list of spec names; configs are merged left-to-right (first-wins).
    specs: Vec<String>,
}

// ---------------------------------------------------------------------------
// Merged config — result of folding all spec entries in a rule together
// ---------------------------------------------------------------------------

/// Fully-resolved config produced by merging all `SpecConfigYaml` entries
/// referenced by a rule.  Every field must be `Some` after merging for a
/// rule to be usable; validation happens in `resolve_rules`.
#[derive(Debug, Clone)]
struct MergedConfig {
    machine_type: String,
    boot_disk_image: String,
    boot_disk_size: u64,
    ip_address: IpAddressType,
    script: String,
    ssh_public_key: String,
    user: String,
    control_plane_endpoint: Option<String>,
}

impl MergedConfig {
    /// Fold an ordered slice of `SpecConfigYaml` references into one
    /// `MergedConfig`.  First non-`None` value wins for each field.
    fn merge(
        rule_specs: &[&str],
        configs: &[&SpecConfigYaml],
    ) -> Result<Self, Box<dyn std::error::Error>> {
        let mut machine_type = None::<String>;
        let mut boot_disk_image = None::<String>;
        let mut boot_disk_size = None::<u64>;
        let mut ip_address = None::<IpAddressType>;
        let mut script = None::<String>;
        let mut ssh_public_key = None::<String>;
        let mut user = None::<String>;
        let mut control_plane_endpoint = None::<String>;

        for cfg in configs {
            if machine_type.is_none() {
                machine_type = cfg.machine_type.clone();
            }
            if boot_disk_image.is_none() {
                boot_disk_image = cfg.boot_disk_image.clone();
            }
            if boot_disk_size.is_none() {
                boot_disk_size = cfg.boot_disk_size;
            }
            if ip_address.is_none() {
                ip_address = cfg.ip_address;
            }
            if script.is_none() {
                script = cfg.script.clone();
            }
            if ssh_public_key.is_none() {
                ssh_public_key = cfg.ssh_public_key.clone();
            }
            if user.is_none() {
                user = cfg.user.clone();
            }
            if control_plane_endpoint.is_none() {
                control_plane_endpoint = cfg.control_plane_endpoint.clone();
            }
        }

        let specs_label = rule_specs.join(", ");

        Ok(Self {
            machine_type: machine_type.ok_or_else(|| {
                format!("Merged specs [{specs_label}] are missing 'machine-type'")
            })?,
            boot_disk_image: boot_disk_image.ok_or_else(|| {
                format!("Merged specs [{specs_label}] are missing 'boot-disk-image'")
            })?,
            boot_disk_size: boot_disk_size.ok_or_else(|| {
                format!("Merged specs [{specs_label}] are missing 'boot-disk-size'")
            })?,
            ip_address: ip_address.unwrap_or(IpAddressType::Private),
            script: script.ok_or_else(|| {
                format!("Merged specs [{specs_label}] are missing 'script'")
            })?,
            ssh_public_key: ssh_public_key.ok_or_else(|| {
                format!("Merged specs [{specs_label}] are missing 'ssh-public-key'")
            })?,
            user: user.ok_or_else(|| {
                format!("Merged specs [{specs_label}] are missing 'user'")
            })?,
            control_plane_endpoint,
        })
    }
}

